def isGood(nums):
    n = max(nums)
    if len(nums) != n + 1:
        return False
    count = [0] * (n + 1)
    for num in nums:
        if num < 1 or num > n:
            return False
        count[num] += 1
    for i in range(1, n):
        if count[i] != 1:
            return False
    return count[n] == 2
